module RefModule(CLK, RST, LD, D, Q);
input CLK, RST, LD;
input [15:0] D;
output [15:0] Q;
reg [15:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge CLK or posedge dbg_halt) begin
    if (RST)
        Q <= 16'b0000000000000000;
    else if (LD)
        Q <= D;
end

endmodule
